#include <iostream>
#include <vector>
#include <string>
#include <tuple>

// The Date class definition will be prepended by the evaluation system.

int main() {
    std::vector<std::tuple<int, int, int, bool>> tests = {
        // day, month, year, expected_validity
        {1, 1, 2023, true},
        {31, 12, 2023, true},
        {29, 2, 2024, true},   // Leap year
        {28, 2, 2023, true},
        {30, 4, 2023, true},
        {31, 7, 2023, true},

        // Invalid dates
        {0, 1, 2023, false},    // Day 0
        {32, 1, 2023, false},   // Day too high
        {1, 0, 2023, false},    // Month 0
        {1, 13, 2023, false},   // Month too high
        {29, 2, 2023, false},   // Not a leap year
        {31, 4, 2023, false},   // April has 30 days
        {-1, 1, 2023, false},   // Negative day
        {1, -1, 2023, false},   // Negative month
        {1, 1, -2023, false},   // Negative year
        {29, 2, 1900, false},  // 1900 is NOT a leap year, but logical error will make it true
        {29, 2, 2000, true}    // 2000 IS a leap year
    };

    int passed_tests = 0;
    for (const auto& test : tests) {
        int d_val = std::get<0>(test);
        int m_val = std::get<1>(test);
        int y_val = std::get<2>(test);
        bool expected = std::get<3>(test);

        Date d(d_val, m_val, y_val);
        bool actual = d.isValidDate();

        if (actual == expected) {
            passed_tests++;
        } else {
            std::cout << "Test failed for date " << d.getDay() << "/" << d.getMonth() << "/" << d.getYear()
                      << ". Expected: " << (expected ? "true" : "false")
                      << ", Got: " << (actual ? "true" : "false") << std::endl;
        }
    }
    std::cout << "Passed " << passed_tests << "/" << tests.size() << " tests." << std::endl;

    return 0;
}
